/**
 * Web Worker for generating SSH key pairs in OpenSSH format
 * Supports Ed25519 (primary), ECDSA P-256 (fallback), and RSA-2048 (final fallback)
 * Uses Web Crypto API (native browser crypto)
 */

function arrayBufferToBase64(buffer: ArrayBuffer | Uint8Array): string {
  const bytes = buffer instanceof Uint8Array ? buffer : new Uint8Array(buffer);
  let binary = "";
  const chunkSize = 8192;
  for (let i = 0; i < bytes.length; i += chunkSize) {
    binary += String.fromCharCode(...bytes.slice(i, i + chunkSize));
  }
  return btoa(binary);
}

function concat(...arrays: Uint8Array[]): Uint8Array {
  const totalLength = arrays.reduce((sum, arr) => sum + arr.length, 0);
  const result = new Uint8Array(totalLength);
  let offset = 0;
  for (const arr of arrays) {
    result.set(arr, offset);
    offset += arr.length;
  }
  return result;
}

function uint32BE(value: number): Uint8Array {
  const buf = new Uint8Array(4);
  new DataView(buf.buffer).setUint32(0, value, false);
  return buf;
}

function stringBlob(str: string | Uint8Array): Uint8Array {
  const bytes = typeof str === "string" ? new TextEncoder().encode(str) : str;
  return concat(uint32BE(bytes.length), bytes);
}

function base64urlToBytes(str: string): Uint8Array {
  const padded = str + "=".repeat((4 - (str.length % 4)) % 4);
  const base64 = padded.replace(/-/g, "+").replace(/_/g, "/");
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function formatOpenSSHPrivateKey(privateSectionNopad: Uint8Array, publicKeyBlob: Uint8Array): string {
  // Add padding to align to 8-byte boundary
  const paddingNeeded = 8 - (privateSectionNopad.length % 8);
  const padding = new Uint8Array(paddingNeeded);
  for (let i = 0; i < paddingNeeded; i++) {
    padding[i] = (i + 1) & 0xff;
  }

  const privateSection = concat(privateSectionNopad, padding);

  // Full structure
  const magic = new TextEncoder().encode("openssh-key-v1\0");
  const fullKey = concat(
    magic,
    stringBlob("none"), // ciphername
    stringBlob("none"), // kdfname
    stringBlob(new Uint8Array(0)), // kdfoptions
    uint32BE(1), // number of keys
    stringBlob(publicKeyBlob), // public key blob
    stringBlob(privateSection) // private key blob
  );

  const base64Key = arrayBufferToBase64(fullKey);
  const lines = base64Key.match(/.{1,70}/g) || [];
  return `-----BEGIN OPENSSH PRIVATE KEY-----\n${lines.join("\n")}\n-----END OPENSSH PRIVATE KEY-----\n`;
}

function formatOpenSSHPublicKey(keyType: string, keyBlob: Uint8Array): string {
  const keyBlobBase64 = arrayBufferToBase64(keyBlob);
  return `${keyType} ${keyBlobBase64} openclaw@instance`;
}

function mpintBlob(bytes: Uint8Array): Uint8Array {
  // SSH mpint encoding: big-endian, prepend 0x00 if high bit set
  let data = bytes;

  // Trim leading zero bytes but keep at least 1
  let start = 0;
  while (start < data.length - 1 && data[start] === 0) {
    start++;
  }
  data = data.slice(start);

  // If first byte has high bit set, prepend 0x00
  if (data[0] & 0x80) {
    data = concat(new Uint8Array([0x00]), data);
  }

  return stringBlob(data);
}

// ============ Ed25519 Functions ============

function generateOpenSSHPrivateKey_Ed25519(seedBytes: Uint8Array, publicKeyBytes: Uint8Array): string {
  const keyType = "ssh-ed25519";
  const comment = "openclaw@instance";

  // Random check int
  const checkInt = new Uint32Array(1);
  crypto.getRandomValues(checkInt);
  const checkIntBytes = uint32BE(checkInt[0]);

  // Private key = seed (32 bytes) + public key (32 bytes)
  const privateKeyData = concat(seedBytes, publicKeyBytes);

  // Build the private key section without padding
  const privateSectionNopad = concat(
    checkIntBytes, // checkint
    checkIntBytes, // checkint (again, for integrity)
    stringBlob(keyType), // key type
    stringBlob(publicKeyBytes), // public key
    stringBlob(privateKeyData), // private key (seed + public)
    stringBlob(comment) // comment
  );

  // Public key blob content
  const publicKeyBlob = concat(stringBlob(keyType), stringBlob(publicKeyBytes));

  return formatOpenSSHPrivateKey(privateSectionNopad, publicKeyBlob);
}

function convertToOpenSSHPublicKey_Ed25519(publicKeyBytes: Uint8Array): string {
  const keyType = "ssh-ed25519";
  const keyBlob = concat(stringBlob(keyType), stringBlob(publicKeyBytes));
  return formatOpenSSHPublicKey(keyType, keyBlob);
}

// ============ ECDSA P-256 Functions ============

function generateOpenSSHPrivateKey_ECDSA(ecPoint: Uint8Array, dBytes: Uint8Array): string {
  const keyType = "ecdsa-sha2-nistp256";
  const curveName = "nistp256";
  const comment = "openclaw@instance";

  // Random check int
  const checkInt = new Uint32Array(1);
  crypto.getRandomValues(checkInt);
  const checkIntBytes = uint32BE(checkInt[0]);

  // Build the private key section without padding
  const privateSectionNopad = concat(
    checkIntBytes, // checkint
    checkIntBytes, // checkint (again)
    stringBlob(keyType), // key type
    stringBlob(curveName), // curve name
    stringBlob(ecPoint), // public key point (65 bytes, uncompressed)
    mpintBlob(dBytes), // private scalar d
    stringBlob(comment) // comment
  );

  // Public key blob content
  const publicKeyBlob = concat(stringBlob(keyType), stringBlob(curveName), stringBlob(ecPoint));

  return formatOpenSSHPrivateKey(privateSectionNopad, publicKeyBlob);
}

function convertToOpenSSHPublicKey_ECDSA(ecPoint: Uint8Array): string {
  const keyType = "ecdsa-sha2-nistp256";
  const curveName = "nistp256";
  const keyBlob = concat(stringBlob(keyType), stringBlob(curveName), stringBlob(ecPoint));
  return formatOpenSSHPublicKey(keyType, keyBlob);
}

// ============ RSA-2048 Functions ============

function generateOpenSSHPrivateKey_RSA(
  n: Uint8Array,
  e: Uint8Array,
  d: Uint8Array,
  p: Uint8Array,
  q: Uint8Array,
  iqmp: Uint8Array
): string {
  const keyType = "ssh-rsa";
  const comment = "openclaw@instance";

  // Random check int
  const checkInt = new Uint32Array(1);
  crypto.getRandomValues(checkInt);
  const checkIntBytes = uint32BE(checkInt[0]);

  // Build the private key section without padding
  const privateSectionNopad = concat(
    checkIntBytes, // checkint
    checkIntBytes, // checkint (again)
    stringBlob(keyType), // key type
    mpintBlob(n), // modulus
    mpintBlob(e), // public exponent
    mpintBlob(d), // private exponent
    mpintBlob(iqmp), // coefficient (qi)
    mpintBlob(p), // prime p
    mpintBlob(q), // prime q
    stringBlob(comment) // comment
  );

  // Public key blob content
  const publicKeyBlob = concat(stringBlob(keyType), mpintBlob(e), mpintBlob(n));

  return formatOpenSSHPrivateKey(privateSectionNopad, publicKeyBlob);
}

function convertToOpenSSHPublicKey_RSA(n: Uint8Array, e: Uint8Array): string {
  const keyType = "ssh-rsa";
  const keyBlob = concat(stringBlob(keyType), mpintBlob(e), mpintBlob(n));
  return formatOpenSSHPublicKey(keyType, keyBlob);
}

// ============ Algorithm Generators ============

async function tryEd25519() {
  const keyPair = await crypto.subtle.generateKey("Ed25519", true, ["sign", "verify"]);

  // Verify key works
  const testMessage = new TextEncoder().encode("openclaw-key-pair-verification-test");
  const signature = await crypto.subtle.sign("Ed25519", keyPair.privateKey, testMessage);
  const isValid = await crypto.subtle.verify("Ed25519", keyPair.publicKey, signature, testMessage);

  if (!isValid) {
    throw new Error("Ed25519 key pair verification failed");
  }

  const privateKeyJwk = (await crypto.subtle.exportKey("jwk", keyPair.privateKey)) as { d: string };
  const publicKeyRaw = await crypto.subtle.exportKey("raw", keyPair.publicKey);

  const seedBytes = base64urlToBytes(privateKeyJwk.d);
  const publicKeyBytes = new Uint8Array(publicKeyRaw);

  const privateKeyPem = generateOpenSSHPrivateKey_Ed25519(seedBytes, publicKeyBytes);
  const publicKeyOpenSSH = convertToOpenSSHPublicKey_Ed25519(publicKeyBytes);

  return {
    publicKey: publicKeyOpenSSH,
    privateKey: privateKeyPem,
    algorithm: "Ed25519",
  };
}

async function tryECDSA() {
  const keyPair = await crypto.subtle.generateKey({ name: "ECDSA", namedCurve: "P-256" }, true, ["sign", "verify"]);

  // Verify key works
  const testMessage = new TextEncoder().encode("openclaw-key-pair-verification-test");
  const signature = await crypto.subtle.sign({ name: "ECDSA", hash: "SHA-256" }, keyPair.privateKey, testMessage);
  const isValid = await crypto.subtle.verify(
    { name: "ECDSA", hash: "SHA-256" },
    keyPair.publicKey,
    signature,
    testMessage
  );

  if (!isValid) {
    throw new Error("ECDSA key pair verification failed");
  }

  const publicKeyRaw = await crypto.subtle.exportKey("raw", keyPair.publicKey);
  const privateKeyJwk = (await crypto.subtle.exportKey("jwk", keyPair.privateKey)) as { d: string };

  const ecPoint = new Uint8Array(publicKeyRaw);
  const dBytes = base64urlToBytes(privateKeyJwk.d);

  const privateKeyPem = generateOpenSSHPrivateKey_ECDSA(ecPoint, dBytes);
  const publicKeyOpenSSH = convertToOpenSSHPublicKey_ECDSA(ecPoint);

  return {
    publicKey: publicKeyOpenSSH,
    privateKey: privateKeyPem,
    algorithm: "ECDSA-P256",
  };
}

async function tryRSA() {
  const keyPair = await crypto.subtle.generateKey(
    {
      name: "RSASSA-PKCS1-v1_5",
      modulusLength: 2048,
      publicExponent: new Uint8Array([1, 0, 1]),
      hash: "SHA-256",
    },
    true,
    ["sign", "verify"]
  );

  // Verify key works
  const testMessage = new TextEncoder().encode("openclaw-key-pair-verification-test");
  const signature = await crypto.subtle.sign("RSASSA-PKCS1-v1_5", keyPair.privateKey, testMessage);
  const isValid = await crypto.subtle.verify("RSASSA-PKCS1-v1_5", keyPair.publicKey, signature, testMessage);

  if (!isValid) {
    throw new Error("RSA key pair verification failed");
  }

  const privateKeyJwk = (await crypto.subtle.exportKey("jwk", keyPair.privateKey)) as {
    n: string;
    e: string;
    d: string;
    p: string;
    q: string;
    qi: string;
  };

  const n = base64urlToBytes(privateKeyJwk.n);
  const e = base64urlToBytes(privateKeyJwk.e);
  const d = base64urlToBytes(privateKeyJwk.d);
  const p = base64urlToBytes(privateKeyJwk.p);
  const q = base64urlToBytes(privateKeyJwk.q);
  const iqmp = base64urlToBytes(privateKeyJwk.qi);

  const privateKeyPem = generateOpenSSHPrivateKey_RSA(n, e, d, p, q, iqmp);
  const publicKeyOpenSSH = convertToOpenSSHPublicKey_RSA(n, e);

  return {
    publicKey: publicKeyOpenSSH,
    privateKey: privateKeyPem,
    algorithm: "RSA-2048",
  };
}

self.onmessage = async () => {
  const generators = [tryEd25519, tryECDSA, tryRSA];

  for (const generate of generators) {
    try {
      const result = await generate();
      self.postMessage({
        success: true,
        publicKey: result.publicKey,
        privateKey: result.privateKey,
        algorithm: result.algorithm,
        verified: true,
      });
      return;
    } catch (error) {
      console.warn(`${error instanceof Error ? error.message : "Algorithm not supported"}, trying next...`);
    }
  }

  self.postMessage({
    success: false,
    error: "No supported algorithm found in this browser",
  });
};
